import requests
import json
import base64

# Dummy base64 image (small)
dummy_img = "data:image/jpeg;base64,"

payload = {
    "name": "tester",
    "images": [dummy_img] * 5
}

try:
    res = requests.post("http://127.0.0.1:5050/api/mobile_register", json=payload)
    print("Status:", res.status_code)
    print("Body:", res.text)
except Exception as e:
    print("Error:", e)
